            color: #e0e6ff;
            min-height: 100vh;
            overflow-x: hidden;
        }

        /* 导航栏 */
        header {
            background: linear-gradient(90deg, rgba(10, 14, 39, 0.95) 0%, rgba(26, 31, 58, 0.95) 100%);
            border-bottom: 2px solid #ff004e;
            padding: 20px 40px;
            position: sticky;
            top: 0;
            z-index: 100;
            box-shadow: 0 0 30px rgba(255, 0, 78, 0.2);
