            font-size: 28px;
            font-weight: bold;
            color: #ff004e;
            text-transform: uppercase;
            letter-spacing: 3px;
            text-shadow: 0 0 20px rgba(255, 0, 78, 0.8);
        }

        nav ul {
            display: flex;
            list-style: none;
            gap: 30px;
        }

        nav a {
            color: #e0e6ff;
            text-decoration: none;
            font-weight: 500;
            padding: 8px 16px;
            border-radius: 4px;
            transition: all 0.3s ease;
            position: relative;
        }

        nav a:hover {
            color: #ff004e;
            background: rgba(255, 0, 78, 0.1);
            box-shadow: 0 0 15px rgba(255, 0, 78, 0.3);
        }

        /* 主容器 */
        .container {
            max-width: 1400px;
            margin: 0 auto;
            padding: 40px 20px;
        }

        /* 标题区域 */
        .header-section {
            text-align: center;
            margin-bottom: 50px;
        }

        h1 {
            font-size: 42px;
            margin-bottom: 10px;
            background: linear-gradient(90deg, #ff004e, #00d4ff);
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
            text-shadow: 0 0 30px rgba(255, 0, 78, 0.5);
        }

        .subtitle {
            color: #8b92b9;
            font-size: 16px;
            font-weight: 300;
        }

        /* 玩家卡片 */
        .player-cards {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
            gap: 25px;
            margin-bottom: 50px;
        }

        .player-card {
            background: linear-gradient(135deg, rgba(26, 31, 58, 0.8) 0%, rgba(42, 50, 92, 0.8) 100%);
            border: 2px solid rgba(255, 0, 78, 0.3);
            border-radius: 12px;
            padding: 30px;
            transition: all 0.3s ease;
            position: relative;
            overflow: hidden;
        }

        .player-card::before {
            content: '';
            position: absolute;
            top: -50%;
            right: -50%;
            width: 100px;
            height: 100px;
            background: radial-gradient(circle, rgba(255, 0, 78, 0.2) 0%, transparent 70%);
            border-radius: 50%;
        }

